export function svgIcon(name) {
  if (ICON_FILES[name]) {
    return `<img class="icon-img" src="${ICON_FILES[name]}" alt="" aria-hidden="true" draggable="false" />`;
  }

  const path = ICONS[name] || ICONS.apps;
  if (path.trim().startsWith("<svg")) {
    return path;
  }
  return `<svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">${path}</svg>`;
}
